package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.FieldNamingStrategy;
import com.google.gson.Gson;
import com.google.gson.JsonIOException;
import com.google.gson.ReflectionAccessFilter;
import com.google.gson.ReflectionAccessFilter.FilterResult;
import com.google.gson.TypeAdapter;
import com.google.gson.reflect.TypeToken;
import com.google.gson.internal.ConstructorConstructor;
import com.google.gson.internal.ObjectConstructor;
import java.lang.reflect.Type;
import java.util.Collections;
import java.util.List;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.ArgumentMatchers;

class ReflectiveTypeAdapterFactoryTest {

  private ConstructorConstructor constructorConstructor;
  private FieldNamingStrategy fieldNamingPolicy;
  private ReflectiveTypeAdapterFactory.JsonAdapterAnnotationTypeAdapterFactory jsonAdapterFactory;
  private Excluder excluder;
  private List<ReflectionAccessFilter> reflectionFilters;
  private ReflectiveTypeAdapterFactory reflectiveTypeAdapterFactory;
  private Gson gson;

  @BeforeEach
  void setUp() {
    constructorConstructor = mock(ConstructorConstructor.class);
    fieldNamingPolicy = mock(FieldNamingStrategy.class);
    jsonAdapterFactory = mock(ReflectiveTypeAdapterFactory.JsonAdapterAnnotationTypeAdapterFactory.class);
    excluder = mock(Excluder.class);
    reflectionFilters = mock(List.class);
    gson = mock(Gson.class);
    reflectiveTypeAdapterFactory = new ReflectiveTypeAdapterFactory(
        constructorConstructor, fieldNamingPolicy, excluder, jsonAdapterFactory, reflectionFilters);
  }

  @Test
  void create_returnsNullForPrimitiveType() {
    TypeToken<Integer> typeToken = TypeToken.get(Integer.class);

    TypeAdapter<Integer> adapter = reflectiveTypeAdapterFactory.create(gson, typeToken);

    assertNull(adapter);
  }

  @Test
  void create_throwsJsonIOExceptionWhenFilterBlocksAll() {
    TypeToken<DummyClass> typeToken = TypeToken.get(DummyClass.class);

    when(reflectionFilters).thenReturn(Collections.emptyList());
    ReflectiveTypeAdapterFactory reflectiveSpy = spy(reflectiveTypeAdapterFactory);
    doReturn(FilterResult.BLOCK_ALL).when(reflectiveSpy)
        .getFilterResult(reflectionFilters, DummyClass.class);

    // Use reflection to replace getFilterResult method call
    // Instead, we will mock ReflectionAccessFilterHelper.getFilterResult static method via wrapper spy
    // Since static mocking is not available, we do a partial refactor: call real method but mock helper class

    // Actually, getFilterResult is called via ReflectionAccessFilterHelper.getFilterResult, which is static.
    // We cannot mock static methods without additional tools, so we test by setting reflectionFilters to a list which returns BLOCK_ALL for DummyClass.

    // Alternative approach: create a new factory with reflectionFilters that cause BLOCK_ALL for DummyClass

    // So we create a custom ReflectionAccessFilter that returns BLOCK_ALL for DummyClass:
    ReflectionAccessFilter filter = new ReflectionAccessFilter() {
      @Override
      public FilterResult checkAccess(Class<?> clazz) {
        if (clazz == DummyClass.class) {
          return FilterResult.BLOCK_ALL;
        }
        return FilterResult.ALLOW;
      }
    };
    ReflectiveTypeAdapterFactory factoryWithFilter = new ReflectiveTypeAdapterFactory(
        constructorConstructor, fieldNamingPolicy, excluder, jsonAdapterFactory, Collections.singletonList(filter));

    JsonIOException ex = assertThrows(JsonIOException.class, () -> {
      factoryWithFilter.create(gson, typeToken);
    });
    assertTrue(ex.getMessage().contains("ReflectionAccessFilter does not permit using reflection for"));
  }

  @Test
  void create_returnsRecordAdapterWhenRawTypeIsRecord() {
    TypeToken<DummyRecord> typeToken = TypeToken.get(DummyRecord.class);

    // Mock ReflectionAccessFilterHelper.getFilterResult to return ALLOW
    ReflectionAccessFilter filter = clazz -> FilterResult.ALLOW;
    ReflectiveTypeAdapterFactory factoryWithFilter = new ReflectiveTypeAdapterFactory(
        constructorConstructor, fieldNamingPolicy, excluder, jsonAdapterFactory, Collections.singletonList(filter));

    // Spy on ReflectionHelper to mock isRecord
    ReflectiveTypeAdapterFactory reflectiveFactorySpy = spy(factoryWithFilter);

    doReturn(true).when(reflectiveFactorySpy).isRecord(DummyRecord.class);
    // Mock getBoundFields to return empty map
    doReturn(Collections.emptyMap()).when(reflectiveFactorySpy)
        .getBoundFields(any(), any(), eq(DummyRecord.class), eq(false), eq(true));

    TypeAdapter<DummyRecord> adapter = reflectiveFactorySpy.create(gson, typeToken);

    assertNotNull(adapter);
    assertEquals("com.google.gson.internal.bind.ReflectiveTypeAdapterFactory$RecordAdapter", adapter.getClass().getName());
  }

  @Test
  void create_returnsFieldReflectionAdapterWhenRawTypeIsNormalClass() {
    TypeToken<DummyClass> typeToken = TypeToken.get(DummyClass.class);

    ReflectionAccessFilter filter = clazz -> FilterResult.ALLOW;
    ReflectiveTypeAdapterFactory factoryWithFilter = new ReflectiveTypeAdapterFactory(
        constructorConstructor, fieldNamingPolicy, excluder, jsonAdapterFactory, Collections.singletonList(filter));

    ObjectConstructor<DummyClass> objectConstructor = mock(ObjectConstructor.class);
    when(constructorConstructor.get(typeToken)).thenReturn(objectConstructor);

    ReflectiveTypeAdapterFactory factorySpy = spy(factoryWithFilter);

    doReturn(false).when(factorySpy).isRecord(DummyClass.class);
    doReturn(Collections.emptyMap()).when(factorySpy)
        .getBoundFields(any(), any(), eq(DummyClass.class), eq(false), eq(false));

    TypeAdapter<DummyClass> adapter = factorySpy.create(gson, typeToken);

    assertNotNull(adapter);
    assertEquals("com.google.gson.internal.bind.ReflectiveTypeAdapterFactory$FieldReflectionAdapter", adapter.getClass().getName());
  }

  // Dummy classes for testing
  private static class DummyClass {}

  private static record DummyRecord(int id) {}

}
